const io = require('socket.io-client');

const TEST_DURATION = 60000; // 60 seconds
const CLIENT_COUNT = 3;
const EXPECTED_EVENTS = 60; // ~1 per second

let serverProcess;
const clients = [];
const clientStats = [];
let testPassed = true;

function startServer() {
  return new Promise((resolve, reject) => {
    serverProcess = spawn('node', ['server.js'], {
      cwd: __dirname,
      stdio: 'pipe'
    });

    let started = false;
    serverProcess.stdout.on('data', (data) => {
      const msg = data.toString();
      if (msg.includes('Server running') && !started) {
        started = true;
        resolve();
      }
    });

    serverProcess.stderr.on('data', (data) => {
      console.error('Server error:', data.toString());
    });

    serverProcess.on('error', reject);

    setTimeout(() => {
      if (!started) reject(new Error('Server did not start in time'));
    }, 10000);
  });
}

function createClient(index) {
  return new Promise((resolve, reject) => {
    const socket = io('http://localhost:3001');
    const stats = { index, events: 0, errors: [] };

    socket.on('connect', () => {
      console.log(`Client ${index} connected`);
    });

    socket.on('system-stats', (data) => {
      stats.events++;
      // Validate payload structure
      if (typeof data.cpuPercent !== 'number' ||
          typeof data.memoryUsed !== 'number' ||
          typeof data.memoryTotal !== 'number' ||
          typeof data.memoryPercent !== 'number' ||
          typeof data.timestamp !== 'number') {
        stats.errors.push('Invalid payload structure at event ' + stats.events);
      }
      if (data.cpuPercent < 0 || data.cpuPercent > 100) {
        stats.errors.push('CPU out of range: ' + data.cpuPercent);
      }
      if (data.memoryPercent < 0 || data.memoryPercent > 100) {
        stats.errors.push('Memory % out of range: ' + data.memoryPercent);
      }
    });

    socket.on('disconnect', () => {
      console.log(`Client ${index} disconnected`);
    });

    socket.on('connect_error', (err) => {
      stats.errors.push('Connect error: ' + err.message);
    });

    clients.push(socket);
    clientStats.push(stats);

    setTimeout(() => resolve(), 2000); // Give time to connect
  });
}

async function runTest() {
  console.log('Starting stability test...');

  try {
    await startServer();
    console.log('Server started');

    // Create multiple clients
    for (let i = 0; i < CLIENT_COUNT; i++) {
      await createClient(i);
    }
    console.log(`${CLIENT_COUNT} clients connected`);

    // Wait for test duration
    await new Promise(resolve => setTimeout(resolve, TEST_DURATION));

    // Evaluate results
    console.log('\n--- Test Results ---');
    for (const stats of clientStats) {
      console.log(`Client ${stats.index}: ${stats.events} events, ${stats.errors.length} errors`);
      if (stats.errors.length > 0) {
        console.log('  Errors:', stats.errors.slice(0, 3));
        testPassed = false;
      }
      if (stats.events < EXPECTED_EVENTS * 0.8) {
        console.log(`  WARNING: Expected ~${EXPECTED_EVENTS} events, got ${stats.events}`);
        testPassed = false;
      }
    }

    if (testPassed) {
      console.log('\n✅ Stability test PASSED');
      process.exit(0);
    } else {
      console.log('\n❌ Stability test FAILED');
      process.exit(1);
    }
  } catch (err) {
    console.error('Test error:', err);
    process.exit(1);
  } finally {
    clients.forEach(c => c.disconnect());
    if (serverProcess) serverProcess.kill();
  }
}

runTest();
","path":"stability-test.js"}

