{"action":"write","content":"const express = require('express');
const { createServer } = require('http');
const { Server } = require('socket.io');
const path = require('path');

const app = express();
const httpServer = createServer(app);
const io = new Server(httpServer);

// Serve static files from the public directory
app.use(express.static(path.join(__dirname, 'public')));

// Serve index.html at root
app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// Socket.IO connection handling
io.on('connection', (socket) => {
  console.log('Client connected:', socket.id);
  socket.on('disconnect', () => {
    console.log('Client disconnected:', socket.id);
  });
});

const PORT = process.env.PORT || 3000;
httpServer.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

module.exports = { io, httpServer };
","path":"server.js"}

{"action":"write","content":"const os = require('os');

let previousCpuInfo = null;

/**
 * Calculate CPU usage percentage by comparing two snapshots of os.cpus().
 * Returns a value between 0 and 100.
 */
function getCpuUsagePercent() {
  const cpus = os.cpus();

  if (!previousCpuInfo) {
    previousCpuInfo = cpus;
    return 0; // Need a baseline; return 0 on first call
  }

  let totalIdle = 0;
  let totalTick = 0;

  for (let i = 0; i < cpus.length; i++) {
    const cpu = cpus[i];
    const prevCpu = previousCpuInfo[i];

    const idleDiff = cpu.times.idle - prevCpu.times.idle;
    const totalDiff =
      (cpu.times.user - prevCpu.times.user) +
      (cpu.times.nice - prevCpu.times.nice) +
      (cpu.times.sys - prevCpu.times.sys) +
      (cpu.times.irq - prevCpu.times.irq) +
      (cpu.times.idle - prevCpu.times.idle);

    totalIdle += idleDiff;
    totalTick += totalDiff;
  }

  previousCpuInfo = cpus;

  if (totalTick === 0) return 0;

  const idlePercent = totalIdle / totalTick;
  const usagePercent = (1 - idlePercent) * 100;
  return Math.max(0, Math.min(100, usagePercent));
}

/**
 * Get memory usage statistics.
 */
function getMemoryStats() {
  const total = os.totalmem();
  const free = os.freemem();
  const used = total - free;
  const percent = (used / total) * 100;

  return {
    total,
    free,
    used,
    percent: Math.max(0, Math.min(100, percent))
  };
}

/**
 * Get combined system stats object.
 */
function getStats() {
  const cpuPercent = getCpuUsagePercent();
  const memory = getMemoryStats();

  return {
    cpuPercent: parseFloat(cpuPercent.toFixed(2)),
    memoryUsed: memory.used,
    memoryTotal: memory.total,
    memoryPercent: parseFloat(memory.percent.toFixed(2)),
    timestamp: Date.now()
  };
}

module.exports = {
  getCpuUsagePercent,
  getMemoryStats,
  getStats
};
","path":"monitor.js"}

