      percent: Math.max(0, Math.min(100, percent))
    };
  } catch (err) {
    console.error('Failed to get disk stats:', err.message);
    return { total: 0, free: 0, used: 0, percent: 0 };
  }
}

/**
 * Get combined system stats object.
 */
async function getStats() {
  const cpuPercent = getCpuUsagePercent();
  const memory = getMemoryStats();
  const disk = await getDiskStats();

  return {
    cpuPercent: parseFloat(cpuPercent.toFixed(2)),
    memoryUsed: memory.used,
    memoryTotal: memory.total,
    memoryPercent: parseFloat(memory.percent.toFixed(2)),
    diskUsed: disk.used,
    diskTotal: disk.total,
    diskPercent: parseFloat(disk.percent.toFixed(2)),
    timestamp: Date.now()
  };
}

module.exports = {
  getCpuUsagePercent,
  getMemoryStats,
  getDiskStats,
  getStats
};
