{"action":"write","content":"const express = require('express');
const { createServer } = require('http');
const { Server } = require('socket.io');
const path = require('path');
const { getStats } = require('./monitor');

const app = express();
const httpServer = createServer(app);
const io = new Server(httpServer);

// Serve static files from the public directory
app.use(express.static(path.join(__dirname, 'public')));

// Serve index.html at root
app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// Socket.IO connection handling
io.on('connection', (socket) => {
  console.log('Client connected:', socket.id);
  socket.on('disconnect', () => {
    console.log('Client disconnected:', socket.id);
  });
});

// Broadcast system stats to all connected clients every 1000 ms
setInterval(async () => {
  try {
    const stats = await getStats();
    io.emit('system-stats', stats);
  } catch (err) {
    console.error('Error broadcasting stats:', err);
  }
}, 1000);

const PORT = process.env.PORT || 3001;
httpServer.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

module.exports = { io, httpServer };
","path":"server.js"}

{"action":"write","content":"const socket = io();

const MAX_DATA_POINTS = 60;

const cpuCtx = document.getElementById('cpu-chart').getContext('2d');
const memoryCtx = document.getElementById('memory-chart').getContext('2d');
const diskCtx = document.getElementById('disk-chart').getContext('2d');

const commonOptions = {
  responsive: true,
  maintainAspectRatio: false,
  animation: false,
  plugins: {
    legend: { display: false }
  },
  scales: {
    x: {
      display: false
    },
    y: {
      beginAtZero: true,
      max: 100,
      ticks: {
        callback: function(value) {
          return value + '%';
        }
      }
    }
  },
  elements: {
    point: {
      radius: 0,
      hitRadius: 0
    },
    line: {
      tension: 0.3,
      borderWidth: 2
    }
  }
};

const cpuChart = new Chart(cpuCtx, {
  type: 'line',
  data: {
    labels: [],
    datasets: [{
      label: 'CPU %',
      data: [],
      borderColor: '#ef4444',
      backgroundColor: 'rgba(239, 68, 68, 0.1)',
      fill: true
    }]
  },
  options: commonOptions
});

const memoryChart = new Chart(memoryCtx, {
  type: 'line',
  data: {
    labels: [],
    datasets: [{
      label: 'Memory %',
      data: [],
      borderColor: '#3b82f6',
      backgroundColor: 'rgba(59, 130, 246, 0.1)',
      fill: true
    }]
  },
  options: commonOptions
});

const diskChart = new Chart(diskCtx, {
  type: 'line',
  data: {
    labels: [],
    datasets: [{
      label: 'Disk %',
      data: [],
      borderColor: '#22c55e',
      backgroundColor: 'rgba(34, 197, 94, 0.1)',
      fill: true
    }]
  },
  options: commonOptions
});

function formatBytes(bytes) {
  const gb = bytes / (1024 * 1024 * 1024);
  return gb.toFixed(2) + ' GB';
}

function updateCharts(stats) {
  const timeLabel = new Date(stats.timestamp).toLocaleTimeString();

  // Update CPU chart
  cpuChart.data.labels.push(timeLabel);
  cpuChart.data.datasets[0].data.push(stats.cpuPercent);
  if (cpuChart.data.labels.length > MAX_DATA_POINTS) {
    cpuChart.data.labels.shift();
    cpuChart.data.datasets[0].data.shift();
  }
  cpuChart.update();

  // Update Memory chart
  memoryChart.data.labels.push(timeLabel);
  memoryChart.data.datasets[0].data.push(stats.memoryPercent);
  if (memoryChart.data.labels.length > MAX_DATA_POINTS) {
    memoryChart.data.labels.shift();
    memoryChart.data.datasets[0].data.shift();
  }
  memoryChart.update();

  // Update Disk chart
  diskChart.data.labels.push(timeLabel);
  diskChart.data.datasets[0].data.push(stats.diskPercent);
  if (diskChart.data.labels.length > MAX_DATA_POINTS) {
    diskChart.data.labels.shift();
    diskChart.data.datasets[0].data.shift();
  }
  diskChart.update();

  // Update numeric readouts
  document.getElementById('cpu-value').textContent = stats.cpuPercent.toFixed(2) + '%';
  document.getElementById('memory-value').textContent = stats.memoryPercent.toFixed(2) + '%';
  document.getElementById('memory-detail').textContent =
    formatBytes(stats.memoryUsed) + ' / ' + formatBytes(stats.memoryTotal);
  document.getElementById('disk-value').textContent = stats.diskPercent.toFixed(2) + '%';
  document.getElementById('disk-detail').textContent =
    formatBytes(stats.diskUsed) + ' / ' + formatBytes(stats.diskTotal);
}

socket.on('connect', () => {
  document.getElementById('connection-status').textContent = 'Connected';
  document.getElementById('connection-status').className = 'connected';
});

socket.on('disconnect', () => {
  document.getElementById('connection-status').textContent = 'Disconnected';
  document.getElementById('connection-status').className = 'disconnected';
});

socket.on('system-stats', (stats) => {
  updateCharts(stats);
});
