{"action":"write","content":"* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
  background: #0f172a;
  color: #e2e8f0;
  min-height: 100vh;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 1.5rem;
}

header {
  text-align: center;
  margin-bottom: 2rem;
}

header h1 {
  font-size: 2rem;
  font-weight: 700;
  color: #f8fafc;
  margin-bottom: 0.25rem;
}

.subtitle {
  color: #94a3b8;
  font-size: 0.95rem;
}

.stats-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.stat-card {
  background: #1e293b;
  border-radius: 12px;
  padding: 1.5rem;
  border: 1px solid #334155;
}

.stat-card h2 {
  font-size: 1.1rem;
  font-weight: 600;
  margin-bottom: 0.75rem;
  color: #cbd5e1;
}

.stat-card.cpu h2 {
  color: #fca5a5;
}

.stat-card.memory h2 {
  color: #93c5fd;
}

.stat-card.disk h2 {
  color: #86efac;
}

.value {
  font-size: 2.5rem;
  font-weight: 700;
  margin-bottom: 0.25rem;
}

.stat-card.cpu .value {
  color: #ef4444;
}

.stat-card.memory .value {
  color: #3b82f6;
}

.stat-card.disk .value {
  color: #22c55e;
}

.detail {
  font-size: 0.9rem;
  color: #94a3b8;
  margin-bottom: 1rem;
}

.chart-container {
  position: relative;
  height: 200px;
  width: 100%;
}

footer {
  text-align: center;
  color: #64748b;
  font-size: 0.85rem;
}

#connection-status {
  font-weight: 600;
}

#connection-status.connected {
  color: #22c55e;
}

#connection-status.disconnected {
  color: #ef4444;
}

/* Responsive: 2 columns on tablet, 3 on desktop */
@media (min-width: 768px) {
  .stats-grid {
    grid-template-columns: 1fr 1fr;
  }

  .chart-container {
    height: 250px;
  }
}

@media (min-width: 1024px) {
  .container {
    padding: 2rem;
  }

  header h1 {
    font-size: 2.5rem;
  }

  .stats-grid {
    grid-template-columns: 1fr 1fr 1fr;
  }

  .chart-container {
    height: 280px;
  }
}
","path":"public/style.css"}

